(window.webpackJsonp=window.webpackJsonp||[]).push([[896],{878:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">s</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxDepth = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">s</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> status=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;s.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(s[i]===<span class=\\"hljs-string\\">\'(\'</span>){\\n            status++\\n            res=<span class=\\"hljs-built_in\\">Math</span>.max(res,status)\\n        }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(s[i]===<span class=\\"hljs-string\\">\')\'</span>){\\n            status--\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-nesting-depth-of-the-parentheses","hasThinking":false,"content":"<p>\u5982\u679c\u5b57\u7b26\u4e32\u6ee1\u8db3\u4ee5\u4e0b\u6761\u4ef6\u4e4b\u4e00\uff0c\u5219\u53ef\u4ee5\u79f0\u4e4b\u4e3a <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong><strong>\uff08valid parentheses string</strong>\uff0c\u53ef\u4ee5\u7b80\u5199\u4e3a <strong>VPS</strong>\uff09\uff1a</p>\\n\\n<ul>\\n\\t<li>\u5b57\u7b26\u4e32\u662f\u4e00\u4e2a\u7a7a\u5b57\u7b26\u4e32 <code>\\"\\"</code>\uff0c\u6216\u8005\u662f\u4e00\u4e2a\u4e0d\u4e3a <code>\\"(\\"</code> \u6216 <code>\\")\\"</code> \u7684\u5355\u5b57\u7b26\u3002</li>\\n\\t<li>\u5b57\u7b26\u4e32\u53ef\u4ee5\u5199\u4e3a <code>AB</code>\uff08<code>A</code> \u4e0e <code>B</code>\xa0\u5b57\u7b26\u4e32\u8fde\u63a5\uff09\uff0c\u5176\u4e2d <code>A</code> \u548c <code>B</code> \u90fd\u662f <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong> \u3002</li>\\n\\t<li>\u5b57\u7b26\u4e32\u53ef\u4ee5\u5199\u4e3a <code>(A)</code>\uff0c\u5176\u4e2d <code>A</code> \u662f\u4e00\u4e2a <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong> \u3002</li>\\n</ul>\\n\\n<p>\u7c7b\u4f3c\u5730\uff0c\u53ef\u4ee5\u5b9a\u4e49\u4efb\u4f55\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\xa0<code>S</code> \u7684 <strong>\u5d4c\u5957\u6df1\u5ea6</strong> <code>depth(S)</code>\uff1a</p>\\n\\n<ul>\\n\\t<li><code>depth(\\"\\") = 0</code></li>\\n\\t<li><code>depth(C) = 0</code>\uff0c\u5176\u4e2d <code>C</code> \u662f\u5355\u4e2a\u5b57\u7b26\u7684\u5b57\u7b26\u4e32\uff0c\u4e14\u8be5\u5b57\u7b26\u4e0d\u662f <code>\\"(\\"</code> \u6216\u8005 <code>\\")\\"</code></li>\\n\\t<li><code>depth(A + B) = max(depth(A), depth(B))</code>\uff0c\u5176\u4e2d <code>A</code> \u548c <code>B</code> \u90fd\u662f <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong></li>\\n\\t<li><code>depth(\\"(\\" + A + \\")\\") = 1 + depth(A)</code>\uff0c\u5176\u4e2d <code>A</code> \u662f\u4e00\u4e2a <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong></li>\\n</ul>\\n\\n<p>\u4f8b\u5982\uff1a<code>\\"\\"</code>\u3001<code>\\"()()\\"</code>\u3001<code>\\"()(()())\\"</code> \u90fd\u662f <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong>\uff08\u5d4c\u5957\u6df1\u5ea6\u5206\u522b\u4e3a 0\u30011\u30012\uff09\uff0c\u800c <code>\\")(\\"</code> \u3001<code>\\"(()\\"</code> \u90fd\u4e0d\u662f <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong> \u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a <strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong> <code>s</code>\uff0c\u8fd4\u56de\u8be5\u5b57\u7b26\u4e32\u7684<em> </em><code>s</code> <strong>\u5d4c\u5957\u6df1\u5ea6</strong> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>s = \\"(1+(2*3)+((<strong>8</strong>)/4))+1\\"\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u6570\u5b57 8 \u5728\u5d4c\u5957\u7684 3 \u5c42\u62ec\u53f7\u4e2d\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>s = \\"(1)+((2))+(((<strong>3</strong>)))\\"\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>s = \\"1+(<strong>2</strong>*3)/(2-1)\\"\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>s = \\"<strong>1</strong>\\"\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= s.length <= 100</code></li>\\n\\t<li><code>s</code> \u7531\u6570\u5b57 <code>0-9</code> \u548c\u5b57\u7b26 <code>\'+\'</code>\u3001<code>\'-\'</code>\u3001<code>\'*\'</code>\u3001<code>\'/\'</code>\u3001<code>\'(\'</code>\u3001<code>\')\'</code> \u7ec4\u6210</li>\\n\\t<li>\u9898\u76ee\u6570\u636e\u4fdd\u8bc1\u62ec\u53f7\u8868\u8fbe\u5f0f <code>s</code> \u662f <strong>\u6709\u6548\u7684\u62ec\u53f7\u8868\u8fbe\u5f0f</strong></li>\\n</ul>\\n","title":"1614. \u62ec\u53f7\u7684\u6700\u5927\u5d4c\u5957\u6df1\u5ea6","relatedTags":["\u5b57\u7b26\u4e32"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1614"}')}}]);